<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">		   &quot;embeddedAppIdList&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wxe5f52902cf4de896&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//需要半屏跳转的小程序appid</span></span>
